#nullable enable // autogenerated

using MVZ2.UI;
using MVZ2Logic.Blueprints;
using MVZ2Logic.Saves;
using PVZEngine;
using PVZEngine.Definitions;
using UnityEngine.EventSystems;

namespace MVZ2.Level
{
    public class ChosenBlueprintController : BlueprintController
    {
        #region 生命周期
        public void Init(ILevelController controller, Blueprint blueprint, int index, SeedDefinition definition)
        {
            Definition = definition;
            InitBlueprint(controller, blueprint, index);
            ui.gameObject.name = definition.GetID().ToString();
            ui.SetDisabled(false);
            ui.SetRecharge(0);
            ui.SetSelected(false);
            ui.SetTwinkleAlpha(0);
        }
        protected override void OnActive()
        {
            base.OnActive();
            ui.OnSelect += OnPointerSelectCallback;
        }
        protected override void OnDeactive()
        {
            base.OnDeactive();
            ui.OnSelect -= OnPointerSelectCallback;
        }
        #endregion

        #region UI
        public override TooltipContent GetTooltipViewData()
        {
            var tooltip = base.GetTooltipViewData();
            var id = Definition.GetID();
            tooltip.error = Controller.BlueprintChoosePart.GetChosenBlueprintTooltipError(Index);
            tooltip.description = Main.ResourceManager.GetBlueprintTooltip(id);
            return tooltip;
        }
        #endregion

        #region 事件回调
        private void OnPointerSelectCallback(Blueprint blueprint, PointerEventData eventData)
        {
            if (!Controller.ChooseBlueprintsInteractable())
                return;
            Controller.BlueprintChoosePart.UnchooseBlueprint(Index);
        }
        #endregion

        public override SeedDefinition GetSeedDefinition()
        {
            return Definition;
        }
        public override bool IsCommandBlock()
        {
            return CommandBlock;
        }
        public NamespaceID GetDefinitionID() => Definition.GetID();
        public BlueprintChooseItem ToChooseItem()
        {
            return new BlueprintChooseItem(GetDefinitionID(), CommandBlock, Innate);
        }
        public BlueprintChooseSaveItem ToChooseSaveItem()
        {
            return new BlueprintChooseSaveItem(GetDefinitionID(), CommandBlock);
        }
        public bool CompareChooseItem(BlueprintChooseItem item)
        {
            return item.id == Definition.GetID() && CommandBlock == item.isCommandBlock;
        }
        public bool CompareChooseSaveItem(BlueprintChooseSaveItem item)
        {
            return item.id == Definition.GetID() && CommandBlock == item.isCommandBlock;
        }
        public bool Innate { get; set; }
        public bool CommandBlock { get; set; }
        public SeedDefinition Definition { get; private set; } = null!;
    }
}
